import{_ as e,o as a,c as r,a4 as d}from"./chunks/framework.BybBnFXO.js";const m=JSON.parse('{"title":"拉长晕彩","description":"","frontmatter":{"title":"拉长晕彩","phenomenon":"labradorescence"},"headers":[],"relativePath":"zh/optical-phenomena/labradorescence.md","filePath":"zh/optical-phenomena/labradorescence.md","lastUpdated":1784176423000}'),o={name:"zh/optical-phenomena/labradorescence.md"};function l(n,t,i,c,h,s){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="拉长晕彩" tabindex="-1">拉长晕彩 <a class="header-anchor" href="#拉长晕彩" aria-label="Permalink to &quot;拉长晕彩&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>拉长石（钙钠长石族）的标志性效应。弧面切割下，内部层状结构 中的纳米级包体或成分交替层对入射光产生反射与干涉，形成强烈 金属感的蓝色、绿色、橙色、金色闪烁，颜色随观察角度连续变化 （即&quot;全息&quot;质感）。与月光石机制相似，但层厚变化更大且层间反 射率差更大，因此效果更鲜艳。最著名的例子是芬兰光谱石 （Spectrolite）。</p><h2 id="机制" tabindex="-1">机制 <a class="header-anchor" href="#机制" aria-label="Permalink to &quot;机制&quot;">​</a></h2><p>成分层状结构：拉长石的钙长石（CaAl₂Si₂O₈）与钠长石 （NaAlSi₃O₈）亚层交替生长，层厚 ~50–250 nm。层间折射率差异 在 0.005–0.012 范围，恰好在可见光干涉条件下产生强烈选择反射。 因视角变化，反射波长发生偏移 → 形成角度依赖的色彩变化。</p><h2 id="示例宝石" tabindex="-1">示例宝石 <a class="header-anchor" href="#示例宝石" aria-label="Permalink to &quot;示例宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>宿主矿物</th><th>晕彩颜色</th></tr></thead><tbody><tr><td>Labradorite / 拉长石</td><td>Plagioclase</td><td>blue-green dominant</td></tr><tr><td>Spectrolite / 光谱石</td><td>Plagioclase</td><td>full spectrum (Finland origin)</td></tr><tr><td>Andesine-Labradorite / 安山-拉长石</td><td>Plagioclase</td><td>green to red</td></tr><tr><td>Spectrolite (Madagascar)</td><td>Plagioclase</td><td>vivid blue-green</td></tr></tbody></table><p><em>详见<a href="./intro.html">光学现象总览</a>。</em></p>',8)])])}const b=e(o,[["render",l]]);export{m as __pageData,b as default};
